import { describe, it, expect } from "vitest";
import {
  resolveTargetCount,
  isEntryComplete,
  entryCompletionRatio,
  countScheduledHabitsForDate,
  weeklyCompletions,
  calculateWeeklyStreak,
} from "./entry-resolution";
import { startOfWeek, addDays, format, subWeeks } from "date-fns";

const habit = (targetCount = 3, weeklyTarget = 3) => ({
  targetCount,
  weeklyTarget,
});

describe("resolveTargetCount", () => {
  it("uses snapshot when present", () => {
    expect(resolveTargetCount({ targetCountSnapshot: 5 }, habit(3))).toBe(5);
  });
  it("falls back to current targetCount when snapshot is undefined", () => {
    expect(resolveTargetCount({ targetCountSnapshot: undefined }, habit(3))).toBe(3);
  });
  it("uses snapshot of 0 over current count (falsy snapshot should still win)", () => {
    // edge: snapshot=0 is a valid recorded value
    expect(resolveTargetCount({ targetCountSnapshot: 0 }, habit(3))).toBe(0);
  });
});

describe("isEntryComplete", () => {
  it("returns true when value meets target", () => {
    expect(isEntryComplete({ value: 3, type: "count", targetCountSnapshot: 3 }, habit())).toBe(true);
  });
  it("returns true when value exceeds target", () => {
    expect(isEntryComplete({ value: 5, type: "count", targetCountSnapshot: 3 }, habit())).toBe(true);
  });
  it("returns false when value is below target", () => {
    expect(isEntryComplete({ value: 2, type: "count", targetCountSnapshot: 3 }, habit())).toBe(false);
  });
  it("returns false for skip entries regardless of value", () => {
    expect(isEntryComplete({ value: 99, type: "skip", targetCountSnapshot: 1 }, habit())).toBe(false);
  });
  it("returns false for fail entries", () => {
    expect(isEntryComplete({ value: 99, type: "fail", targetCountSnapshot: 1 }, habit())).toBe(false);
  });
  it("uses snapshot over current targetCount", () => {
    // snapshot=10, current=1; value=5 should be incomplete
    expect(isEntryComplete({ value: 5, type: "count", targetCountSnapshot: 10 }, habit(1))).toBe(false);
  });
});

describe("entryCompletionRatio", () => {
  it("returns 1.0 at exactly target", () => {
    expect(entryCompletionRatio({ value: 3, targetCountSnapshot: 3 }, habit(3))).toBe(1);
  });
  it("returns partial ratio", () => {
    expect(entryCompletionRatio({ value: 1, targetCountSnapshot: 4 }, habit())).toBe(0.25);
  });
  it("returns 0 when target is 0 (avoids division by zero)", () => {
    expect(entryCompletionRatio({ value: 5, targetCountSnapshot: 0 }, habit(0))).toBe(0);
  });
  it("can exceed 1.0 for over-achievement", () => {
    expect(entryCompletionRatio({ value: 6, targetCountSnapshot: 3 }, habit(3))).toBe(2);
  });
});

describe("countScheduledHabitsForDate", () => {
  it("returns 0 for undefined habits", () => {
    expect(countScheduledHabitsForDate(undefined, "2024-01-15")).toBe(0);
  });
  it("excludes weekly_target habits", () => {
    const h = { frequency: "weekly_target", createdAt: "2024-01-01", scheduledDays: [] } as any;
    expect(countScheduledHabitsForDate([h], "2024-01-15")).toBe(0);
  });
  it("excludes habits created after the date", () => {
    const h = { frequency: "daily", createdAt: "2024-01-20", scheduledDays: [] } as any;
    expect(countScheduledHabitsForDate([h], "2024-01-15")).toBe(0);
  });
  it("counts habits with no scheduledDays for any day", () => {
    const h = { frequency: "daily", createdAt: "2024-01-01", scheduledDays: [] } as any;
    expect(countScheduledHabitsForDate([h], "2024-01-15")).toBe(1);
  });
  it("counts habits scheduled on the matching day-of-week", () => {
    // 2024-01-15 is a Monday (dow=1)
    const mon = { frequency: "daily", createdAt: "2024-01-01", scheduledDays: [1] } as any;
    const tue = { frequency: "daily", createdAt: "2024-01-01", scheduledDays: [2] } as any;
    expect(countScheduledHabitsForDate([mon, tue], "2024-01-15")).toBe(1);
  });
});

describe("weeklyCompletions", () => {
  it("counts days with completed entries in the week", () => {
    const weekStart = new Date("2024-01-15"); // Monday
    const entryMap = new Map([
      ["2024-01-15", { value: 3, targetCountSnapshot: 3 }],
      ["2024-01-16", { value: 3, targetCountSnapshot: 3 }],
      ["2024-01-17", { value: 1, targetCountSnapshot: 3 }], // incomplete
    ]);
    expect(weeklyCompletions(entryMap, weekStart, habit(3))).toBe(2);
  });
  it("ignores skip/fail entries", () => {
    const weekStart = new Date("2024-01-15");
    const entryMap = new Map([
      ["2024-01-15", { value: 3, type: "skip", targetCountSnapshot: 3 }],
    ]);
    expect(weeklyCompletions(entryMap, weekStart, habit(3))).toBe(0);
  });
  it("returns 0 for an empty map", () => {
    expect(weeklyCompletions(new Map(), new Date("2024-01-15"), habit())).toBe(0);
  });
});

describe("calculateWeeklyStreak", () => {
  // Note: this function uses `new Date()` internally so tests are time-sensitive.
  // Smoke-test the return type and that a fulfilled current week = at least 1.
  it("returns a non-negative integer", () => {
    const streak = calculateWeeklyStreak(new Map(), habit());
    expect(typeof streak).toBe("number");
    expect(streak).toBeGreaterThanOrEqual(0);
  });
  it("returns 0 when no entries exist", () => {
    expect(calculateWeeklyStreak(new Map(), habit(3, 3))).toBe(0);
  });
});
