import { describe, it, expect } from "vitest";
import {
  countWords,
  countWordsFromJSON,
  countWordsFromContent,
  isJsonContent,
  type JSONContentNode,
} from "./text";

describe("countWords (HTML)", () => {
  it("counts plain text words", () => {
    expect(countWords("hello world")).toBe(2);
  });
  it("strips HTML tags before counting", () => {
    expect(countWords("<p>hello <strong>world</strong></p>")).toBe(2);
  });
  it("handles &nbsp; entities", () => {
    expect(countWords("a&nbsp;b")).toBe(2);
  });
  it("returns 0 for empty string", () => {
    expect(countWords("")).toBe(0);
  });
  it("returns 0 for tags-only content", () => {
    expect(countWords("<br/><p></p>")).toBe(0);
  });
  it("collapses multiple spaces", () => {
    expect(countWords("  one   two  ")).toBe(2);
  });
});

describe("countWordsFromJSON", () => {
  const doc: JSONContentNode = {
    type: "doc",
    content: [
      {
        type: "paragraph",
        content: [
          { type: "text", text: "Hello " },
          { type: "text", text: "world" },
        ],
      },
    ],
  };

  it("counts words in a TipTap doc", () => {
    expect(countWordsFromJSON(doc)).toBe(2);
  });
  it("returns 0 for undefined", () => {
    expect(countWordsFromJSON(undefined)).toBe(0);
  });
  it("returns 0 for an empty doc", () => {
    expect(countWordsFromJSON({ type: "doc", content: [] })).toBe(0);
  });
  it("handles deeply nested content", () => {
    const nested: JSONContentNode = {
      type: "doc",
      content: [{ type: "blockquote", content: [{ type: "paragraph", content: [{ type: "text", text: "deep" }] }] }],
    };
    expect(countWordsFromJSON(nested)).toBe(1);
  });
});

describe("isJsonContent", () => {
  it("returns true for objects", () => {
    expect(isJsonContent({ type: "doc" })).toBe(true);
  });
  it("returns false for strings", () => {
    expect(isJsonContent("<p>hi</p>")).toBe(false);
  });
  it("returns false for null", () => {
    expect(isJsonContent(null)).toBe(false);
  });
  it("returns false for undefined", () => {
    expect(isJsonContent(undefined)).toBe(false);
  });
});

describe("countWordsFromContent (unified)", () => {
  it("dispatches to HTML counter for strings", () => {
    expect(countWordsFromContent("<p>one two</p>")).toBe(2);
  });
  it("dispatches to JSON counter for objects", () => {
    expect(countWordsFromContent({ type: "text", text: "one two three" })).toBe(3);
  });
  it("returns 0 for null", () => {
    expect(countWordsFromContent(null)).toBe(0);
  });
  it("returns 0 for undefined", () => {
    expect(countWordsFromContent(undefined)).toBe(0);
  });
});
