import { describe, it, expect, vi, beforeEach } from "vitest";
import { NotFoundException } from "@nestjs/common";
import { HabitService } from "./habit.service";
import type { HabitRepository } from "./habit.repository";
import { Habit } from "./habit.entity";
import * as entitlement from "../../common/helpers/entitlement";

const mockRepo = (): jest.Mocked<HabitRepository> =>
  ({
    countActiveForUser: vi.fn(),
    save: vi.fn(),
    findByUser: vi.fn(),
    findByUserPaginated: vi.fn(),
    findUpdatedSince: vi.fn(),
    findById: vi.fn(),
    delete: vi.fn(),
    deleteAllForUser: vi.fn(),
  }) as any;

const stubUser = { sub: "user-1", entitlements: { max_habits: 50 } } as any;

describe("HabitService", () => {
  let service: HabitService;
  let repo: ReturnType<typeof mockRepo>;

  beforeEach(() => {
    repo = mockRepo();
    service = new HabitService(repo);
    vi.spyOn(entitlement, "enforceLimit").mockResolvedValue(undefined);
  });

  describe("create", () => {
    it("calls enforceLimit then saves the new habit", async () => {
      const dto = { name: "Read", frequency: "daily", targetCount: 1 } as any;
      repo.save.mockResolvedValue(undefined);
      const habit = await service.create("user-1", dto, stubUser);
      expect(entitlement.enforceLimit).toHaveBeenCalled();
      expect(repo.save).toHaveBeenCalledWith(habit);
      expect(habit.name).toBe("Read");
    });
  });

  describe("findById", () => {
    it("returns the habit when found", async () => {
      const h = { id: "h1" } as Habit;
      repo.findById.mockResolvedValue(h);
      await expect(service.findById("user-1", "h1")).resolves.toBe(h);
    });
    it("throws NotFoundException when not found", async () => {
      repo.findById.mockResolvedValue(null);
      await expect(service.findById("user-1", "missing")).rejects.toThrow(NotFoundException);
    });
  });

  describe("listByUser", () => {
    it("delegates to repository with clamped page/limit", async () => {
      repo.findByUserPaginated.mockResolvedValue({ docs: [], total: 0 });
      await service.listByUser("user-1", 0, 9999);
      const [, page, limit] = repo.findByUserPaginated.mock.calls[0]!;
      expect(page).toBeGreaterThanOrEqual(1);
      expect(limit).toBeLessThanOrEqual(500);
    });
  });

  describe("delete", () => {
    it("calls findById then repository.delete", async () => {
      repo.findById.mockResolvedValue({ id: "h1" } as Habit);
      repo.delete.mockResolvedValue(undefined);
      await service.delete("user-1", "h1");
      expect(repo.delete).toHaveBeenCalledWith("user-1", "h1");
    });
    it("propagates NotFoundException if habit missing", async () => {
      repo.findById.mockResolvedValue(null);
      await expect(service.delete("user-1", "ghost")).rejects.toThrow(NotFoundException);
    });
  });

  describe("deleteAllForUser", () => {
    it("delegates to repository and returns count", async () => {
      repo.deleteAllForUser.mockResolvedValue(7);
      expect(await service.deleteAllForUser("user-1")).toBe(7);
    });
  });
});
