import { describe, it, expect } from "vitest";
import { encryptField, decryptField, encryptJournal, decryptJournal } from "./cipher";
import { generateDEK } from "./keys";

describe("encryptField / decryptField", () => {
  it("round-trips a plaintext string", async () => {
    const dek = await generateDEK();
    const plaintext = "my secret journal entry";
    const encoded = await encryptField(plaintext, dek);
    const decoded = await decryptField(encoded, dek);
    expect(decoded).toBe(plaintext);
  });

  it("produces different ciphertexts for the same plaintext (random IV)", async () => {
    const dek = await generateDEK();
    const a = await encryptField("same", dek);
    const b = await encryptField("same", dek);
    expect(a).not.toBe(b);
  });

  it("round-trips an empty string", async () => {
    const dek = await generateDEK();
    expect(await decryptField(await encryptField("", dek), dek)).toBe("");
  });

  it("round-trips unicode content", async () => {
    const dek = await generateDEK();
    const text = "日本語テスト 🔐";
    expect(await decryptField(await encryptField(text, dek), dek)).toBe(text);
  });

  it("throws on wrong DEK", async () => {
    const dek1 = await generateDEK();
    const dek2 = await generateDEK();
    const encoded = await encryptField("secret", dek1);
    await expect(decryptField(encoded, dek2)).rejects.toThrow();
  });

  it("throws on tampered ciphertext", async () => {
    const dek = await generateDEK();
    const encoded = await encryptField("secret", dek);
    // Flip a byte in the base64 body
    const tampered = encoded.slice(0, -4) + "AAAA";
    await expect(decryptField(tampered, dek)).rejects.toThrow();
  });
});

describe("encryptJournal / decryptJournal", () => {
  it("round-trips all fields", async () => {
    const dek = await generateDEK();
    const data = { title: "My Day", content: "<p>Hello</p>", tags: ["personal", "work"] };
    const encrypted = await encryptJournal(data, dek);
    const decrypted = await decryptJournal(encrypted, dek);
    expect(decrypted).toEqual(data);
  });

  it("encrypts each field independently (different ciphertexts)", async () => {
    const dek = await generateDEK();
    const { title, content } = await encryptJournal(
      { title: "same", content: "same", tags: [] },
      dek,
    );
    expect(title).not.toBe(content);
  });

  it("round-trips an empty tags array", async () => {
    const dek = await generateDEK();
    const result = await decryptJournal(
      await encryptJournal({ title: "t", content: "c", tags: [] }, dek),
      dek,
    );
    expect(result.tags).toEqual([]);
  });
});

import { describe, it, expect } from "vitest";
import {
  generateSalt,
  deriveMasterKey,
  generateDEK,
  wrapDEK,
  unwrapDEK,
  toBase64,
  fromBase64,
  saltToBase64,
  saltFromBase64,
  deriveRecoveryMasterKey,
} from "./keys";

describe("generateSalt", () => {
  it("produces a 16-byte Uint8Array", () => {
    const salt = generateSalt();
    expect(salt).toBeInstanceOf(Uint8Array);
    expect(salt.length).toBe(16);
  });
  it("produces different values each call", () => {
    expect(toBase64(generateSalt())).not.toBe(toBase64(generateSalt()));
  });
});

describe("toBase64 / fromBase64", () => {
  it("round-trips a byte array", () => {
    const bytes = new Uint8Array([1, 2, 3, 255, 0]);
    expect(fromBase64(toBase64(bytes))).toEqual(bytes);
  });
  it("accepts ArrayBuffer input", () => {
    const buf = new Uint8Array([10, 20]).buffer;
    expect(fromBase64(toBase64(buf))).toEqual(new Uint8Array([10, 20]));
  });
});

describe("saltToBase64 / saltFromBase64", () => {
  it("round-trips a salt", () => {
    const salt = generateSalt();
    expect(saltFromBase64(saltToBase64(salt))).toEqual(salt);
  });
});

describe("deriveMasterKey", () => {
  it("derives a key without throwing", async () => {
    const salt = generateSalt();
    const key = await deriveMasterKey("correct horse battery staple", salt);
    expect(key).toBeDefined();
  });
  it("produces different keys for different passphrases", async () => {
    const salt = generateSalt();
    const k1 = await wrapDEK(await generateDEK(), await deriveMasterKey("pass1", salt));
    const k2 = await wrapDEK(await generateDEK(), await deriveMasterKey("pass2", salt));
    // Just assert they both succeed (key material is opaque CryptoKey)
    expect(k1).not.toBe(k2);
  });
});

describe("wrapDEK / unwrapDEK", () => {
  it("round-trips a DEK", async () => {
    const salt = generateSalt();
    const masterKey = await deriveMasterKey("passphrase", salt);
    const dek = await generateDEK();
    const wrapped = await wrapDEK(dek, masterKey);
    const unwrapped = await unwrapDEK(wrapped, masterKey);
    expect(unwrapped).toBeDefined();
  });

  it("fails to unwrap with wrong master key", async () => {
    const dek = await generateDEK();
    const mk1 = await deriveMasterKey("correct", generateSalt());
    const mk2 = await deriveMasterKey("wrong", generateSalt());
    const wrapped = await wrapDEK(dek, mk1);
    await expect(unwrapDEK(wrapped, mk2)).rejects.toThrow();
  });
});

describe("deriveRecoveryMasterKey", () => {
  it("derives the same key regardless of code order", async () => {
    const codes = ["CODE1", "CODE2", "CODE3"];
    const shuffled = ["CODE3", "CODE1", "CODE2"];
    const sub = "user-sub-123";
    // Both should produce a valid (usable) key — wrap/unwrap to verify equivalence
    const dek = await generateDEK();
    const mk1 = await deriveRecoveryMasterKey(codes, sub);
    const mk2 = await deriveRecoveryMasterKey(shuffled, sub);
    const wrapped = await wrapDEK(dek, mk1);
    // Same key → unwrap must succeed
    await expect(unwrapDEK(wrapped, mk2)).resolves.toBeDefined();
  });
});

import { describe, it, expect } from "vitest";
import { generateRecoveryCodes, hashRecoveryCodes } from "./recovery";

const CHARSET = /^[ABCDEFGHJKLMNPQRSTUVWXYZ23456789]+$/;

describe("generateRecoveryCodes", () => {
  it("generates the requested count (default 8)", () => {
    expect(generateRecoveryCodes()).toHaveLength(8);
    expect(generateRecoveryCodes(4)).toHaveLength(4);
  });
  it("each code is 8 characters from the safe charset", () => {
    const codes = generateRecoveryCodes();
    for (const code of codes) {
      expect(code).toHaveLength(8);
      expect(CHARSET.test(code)).toBe(true);
    }
  });
  it("never produces ambiguous characters (0 1 I O)", () => {
    const codes = generateRecoveryCodes(100);
    const all = codes.join("");
    expect(all).not.toMatch(/[01IO]/);
  });
  it("produces unique codes (statistically)", () => {
    const codes = generateRecoveryCodes(8);
    expect(new Set(codes).size).toBe(8);
  });
});

describe("hashRecoveryCodes", () => {
  it("returns a non-empty base64 string", async () => {
    const hash = await hashRecoveryCodes(["CODE1", "CODE2"]);
    expect(typeof hash).toBe("string");
    expect(hash.length).toBeGreaterThan(0);
  });
  it("produces the same hash regardless of input order", async () => {
    const h1 = await hashRecoveryCodes(["A", "B", "C"]);
    const h2 = await hashRecoveryCodes(["C", "A", "B"]);
    expect(h1).toBe(h2);
  });
  it("produces different hashes for different code sets", async () => {
    const h1 = await hashRecoveryCodes(["A", "B"]);
    const h2 = await hashRecoveryCodes(["X", "Y"]);
    expect(h1).not.toBe(h2);
  });
});

import { describe, it, expect, vi, beforeEach } from "vitest";
import { NotFoundException } from "@nestjs/common";
import { HabitService } from "./habit.service";
import type { HabitRepository } from "./habit.repository";
import { Habit } from "./habit.entity";
import * as entitlement from "../../common/helpers/entitlement";

const mockRepo = (): jest.Mocked<HabitRepository> =>
  ({
    countActiveForUser: vi.fn(),
    save: vi.fn(),
    findByUser: vi.fn(),
    findByUserPaginated: vi.fn(),
    findUpdatedSince: vi.fn(),
    findById: vi.fn(),
    delete: vi.fn(),
    deleteAllForUser: vi.fn(),
  }) as any;

const stubUser = { sub: "user-1", entitlements: { max_habits: 50 } } as any;

describe("HabitService", () => {
  let service: HabitService;
  let repo: ReturnType<typeof mockRepo>;

  beforeEach(() => {
    repo = mockRepo();
    service = new HabitService(repo);
    vi.spyOn(entitlement, "enforceLimit").mockResolvedValue(undefined);
  });

  describe("create", () => {
    it("calls enforceLimit then saves the new habit", async () => {
      const dto = { name: "Read", frequency: "daily", targetCount: 1 } as any;
      repo.save.mockResolvedValue(undefined);
      const habit = await service.create("user-1", dto, stubUser);
      expect(entitlement.enforceLimit).toHaveBeenCalled();
      expect(repo.save).toHaveBeenCalledWith(habit);
      expect(habit.name).toBe("Read");
    });
  });

  describe("findById", () => {
    it("returns the habit when found", async () => {
      const h = { id: "h1" } as Habit;
      repo.findById.mockResolvedValue(h);
      await expect(service.findById("user-1", "h1")).resolves.toBe(h);
    });
    it("throws NotFoundException when not found", async () => {
      repo.findById.mockResolvedValue(null);
      await expect(service.findById("user-1", "missing")).rejects.toThrow(NotFoundException);
    });
  });

  describe("listByUser", () => {
    it("delegates to repository with clamped page/limit", async () => {
      repo.findByUserPaginated.mockResolvedValue({ docs: [], total: 0 });
      await service.listByUser("user-1", 0, 9999);
      const [, page, limit] = repo.findByUserPaginated.mock.calls[0]!;
      expect(page).toBeGreaterThanOrEqual(1);
      expect(limit).toBeLessThanOrEqual(500);
    });
  });

  describe("delete", () => {
    it("calls findById then repository.delete", async () => {
      repo.findById.mockResolvedValue({ id: "h1" } as Habit);
      repo.delete.mockResolvedValue(undefined);
      await service.delete("user-1", "h1");
      expect(repo.delete).toHaveBeenCalledWith("user-1", "h1");
    });
    it("propagates NotFoundException if habit missing", async () => {
      repo.findById.mockResolvedValue(null);
      await expect(service.delete("user-1", "ghost")).rejects.toThrow(NotFoundException);
    });
  });

  describe("deleteAllForUser", () => {
    it("delegates to repository and returns count", async () => {
      repo.deleteAllForUser.mockResolvedValue(7);
      expect(await service.deleteAllForUser("user-1")).toBe(7);
    });
  });
});
